    # Handle edge cases
    if n < 2:
        return factors

    # Check for factor of 2
    while n % 2 == 0:
        factors.append(2)
        n //= 2

    # Check for odd factors starting from 3
    factor = 3
    while factor * factor <= n:
        while n % factor == 0:
            factors.append(factor)
            n //= factor
        factor += 2

    # If n becomes a prime number greater than 2
    if n > 2:
        factors.append(n)

    return factors",
